import java.util.*;

public class RoundRobinLoadBalancer {

    private final List<String> instances = new ArrayList<>();
    private int currentIndex = 0;

    public void addInstance(String instanceAddress) {
        instances.add(instanceAddress);
    }

    public void removeInstance(String instanceAddress) {
        int idx = instances.indexOf(instanceAddress);
        if (idx >= 0) {
            instances.remove(idx);
            if (currentIndex >= instances.size() && !instances.isEmpty()) {
                currentIndex = 0;
            }
        }
    }

    public String chooseInstance() {
        // Return the next instance in round-robin order
        // Return null if no instances are registered
        return null;
    }

    public List<String> simulateRequests(int count) {
        // Return list of instance addresses chosen for 'count' sequential requests
        List<String> chosen = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            chosen.add(chooseInstance());
        }
        return chosen;
    }

    public static void main(String[] args) {
        RoundRobinLoadBalancer lb = new RoundRobinLoadBalancer();
        lb.addInstance("10.0.0.1:8080");
        lb.addInstance("10.0.0.2:8080");
        lb.addInstance("10.0.0.3:8080");

        List<String> results = lb.simulateRequests(6);
        results.forEach(System.out::println);
    }
}

